  v_delay      NUMBER := 5; -- Delay in seconds
BEGIN
  v_start_time := SYSTIMESTAMP;

  -- Conditional delay: only sleep if condition is true
  IF (SELECT SUBSTR(SYS_CONTEXT('USERENV','SESSION_USER'),1,1) FROM DUAL) = 'A' THEN
