  v_end_time := SYSTIMESTAMP;

  -- Optional: Log or return timing for debugging (not in production)
  DBMS_OUTPUT.PUT_LINE('Elapsed: ' || EXTRACT(SECOND FROM (v_end_time - v_start_time)));
END;
/

