BEARER_TOKEN = "your_bearer_token_here"  # Obtained via developer portal, never hardcoded in production

def post_tweet(text):
    url = "https://api.x.com/2/tweets"
    headers = {
        "Authorization": f"Bearer {BEARER_TOKEN}",
        "Content-Type": "application/json"
